var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"단단히 미쳤어.","JPN":"狂ってる。","ENG":"You're completely insane.","TWN":"真是瘋了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"왜 이제 와서 이 일에 열을 내는 거지?","JPN":"なぜ今更この件にこだわる？","ENG":"Why are you so worked up now?","TWN":"為什麼現在才對這件事這麼費勁？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"참견해봤자 자네에게 전혀 득이 없는 일인데.","JPN":"首を突っ込んだところで、君に得はないはずだ。","ENG":"Getting involved doesn't benefit you in any way.","TWN":"插手這件事對你一點好處都沒有。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"알 필요 없잖아!","JPN":"あなたには関係ない！","ENG":"Like I need a reason!","TWN":"你不需要知道！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"윽……! 그 모습은?","JPN":"っ……！　その姿は？","ENG":"Ugh...! Your arm...!","TWN":"呃……！那是？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"침식 증후군이라는 거짓말을 해서 미안하군.","JPN":"侵食症候群なんて嘘をついてすまなかったな。","ENG":"Apologies for the deception. I never had Corruption Syndrome.","TWN":"對不起，我撒謊說這是侵蝕症候群。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"나도 <color=#ffd34c>붉은 달 현상</color>의 감염자였네.","JPN":"私も<color=#ffd34c>赤い月現象</color>の感染者でね。","ENG":"I was afflicted by the <color=#ffd34c>Red Moon phenomenon</color>.","TWN":"其實我也是<color=#ffd34c>紅月現象</color>的感染者啊。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네와는 다르게, 반쪽짜리지만 말일세.","JPN":"まあ、君とは違って半端者だけど。","ENG":"Unlike you, though, I'm only half-afflicted.","TWN":"我和你不一樣，我只是個半吊子。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"何だって……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"나는 내 몸을 갉아먹는 광증을 이겨내기 위해 연구를 시작했네.","JPN":"私はこの体を蝕む狂症を乗り越えるために研究を始めた。","ENG":"I started my research to overcome the madness eating away at me.","TWN":"我開始研究如何戰勝吞噬我身體的狂症。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"처음엔 가문의 식솔들을 사용했지.","JPN":"最初は家の者たちを使ったよ。","ENG":"At first, I used my own household servants.","TWN":"一開始我用了家裡的僕人。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"내 인자를 주사하기 가장 손쉬운 자들이었으니.","JPN":"私のファクターを注入する実験体としては、うってつけだったからね。","ENG":"They were the most convenient test subjects.","TWN":"他們是最容易注入我基因的人。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 묘지에서 본 시체는……?","JPN":"じゃあ、墓地で見た死体は……？","ENG":"Then the corpse in the graveyard was...","TWN":"那麼在墓地看到的屍體是……？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"가장 마지막까지 남은 사용인이지.","JPN":"最後まで生き残っていた使用人さ。","ENG":"My last remaining servant.","TWN":"是最後留下來的實驗品。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"도망치려다 침식체에게 죽은 건 아쉬운 일이었지만.","JPN":"逃げようとして侵食体に殺されてしまったのはとても残念だった。","ENG":"One tried to escape but was devoured by a C.O. A shame, really.","TWN":"在逃跑時被侵蝕體殺死了，真是可惜。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"실험은 순조롭지 못했어.","JPN":"実験は順調ではなかった。","ENG":"The experiments didn't go well.","TWN":"實驗不太順利。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"변이는 성공했으나 광증이 발현하기 일쑤였지.","JPN":"変異には成功したものの、狂症が発現しがちだった。","ENG":"While I succeeded in inducing mutations, the madness was uncontrollable.","TWN":"變異雖然成功了，但狂症時常出現。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네에게 억지로 광증을 일으킨 것과 다르게 말일세.","JPN":"君に無理矢理狂症を起こしたのとは違ってね。","ENG":"Unlike what I forced onto you.","TWN":"和強行讓你發狂不同。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"수많은 실패 끝에, 나는 깨닫고 말았어.","JPN":"数多の失敗の末に、私は気づいてしまったのだよ。","ENG":"After countless failures, I came to a realization.","TWN":"經歷了無數次失敗後，我終於明白了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"내 반쪽짜리 인자로는 절대 연구를 완성할 수 없다는 것을.","JPN":"私のこの中途半端なファクターでは、決して研究を完成できないということに。","ENG":"That my half-factor would never be enough to complete my research.","TWN":"憑我那半吊子的資質，絕對無法完成研究。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당신 식솔들을 실험에 이용했다고?","JPN":"自分の家の者たちを実験に利用しただって……？","ENG":"You experimented on your own people?!","TWN":"你竟然把你的家人用於實驗？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"혁신을 위한 희생이지.","JPN":"革新を遂げるための犠牲さ。","ENG":"A necessary sacrifice for progress.","TWN":"為了革新而犧牲。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"이 고착 상태가 지속됐다면, 난 분명 포기했을 걸세.","JPN":"あの行き止まり状態が続いたら、私はきっと諦めていた。","ENG":"Had I remained stuck, I would have definitely given up.","TWN":"如果這種僵局持續下去，我肯定會放棄的。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"실제로 연구한 흔적을 없애기 위해 자네를 이용하기도 했고.","JPN":"実際、研究の痕跡を消すために君を利用したしね。","ENG":"In fact, I even used you to cover my tracks.","TWN":"實際上也利用了你來消除研究的痕跡。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"はあ……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 심령 현상이라고 날 부른 건…….","JPN":"それじゃあ、心霊現象とか言って私を呼んだのは……","ENG":"So calling me for an exorcism was just–","TWN":"那麼叫我來處理靈異現象的事情……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"하지만, 지금은 사정이 달라졌어.","JPN":"しかし、今は状況が変わったんだ。","ENG":"But now, things are different.","TWN":"但現在情況不同了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"나는 학자라네. 심령 현상이란 건 과학적으로 증명되지 않았을 뿐.","JPN":"私は学者だ。心霊現象はまだ科学的に証明されていないだけで……","ENG":"I'm a scientist. \\"Hauntings\\" are just unproven theories.","TWN":"我是個學者，所謂的靈異現象只是尚未被科學證明而已。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그 본질은 침식 현상 아니겠나?","JPN":"本質は侵食現象だろう。","ENG":"What people call ghosts are nothing more than the Corruption at work.","TWN":"其本質不就是侵蝕現象嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래서 돈을 달라는 대로 준다고 했던 거였어?","JPN":"だから金はいくらでも出すって言ったわけね。","ENG":"So that's why you were willing to pay me whatever I asked?","TWN":"所以你才會同意我說的金額嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"난 그냥 치매 걸린 호구를 하나 잡은 줄 알았지!","JPN":"私はボケたカモだとばかり……！","ENG":"I thought I'd just found some senile old fool to scam!","TWN":"我還以為是運氣好碰到一個盤子！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 내가 감염자라는 건 어떻게 안 거야?","JPN":"じゃあ、私が感染者だってことはどうやってわかった？","ENG":"Then how did you know I was afflicted?!","TWN":"那你是怎麼知道我是感染者的？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"처음엔 붉은 달 현상의 침식파 냄새를 맡았을 때였네.","JPN":"赤い月現象の侵食波の匂いを嗅いだ時だった。","ENG":"At first, it was the scent of the Corruption rays from the Red Moon phenomenon.","TWN":"最初是聞到紅月現象的侵蝕波時。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그땐 그저 의심하는 정도였지만…….","JPN":"あの時はもしかしたら、と思っただけだったが……","ENG":"Back then, I only had my suspicions...","TWN":"那時只是有些懷疑……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"제가…… 이성을 잃은 동안 무슨 일이 있었죠?","JPN":"私が……理性を失っている間、何があったんですか？","ENG":"So... what exactly happened while I was out of it?","TWN":"我……失去理智的這段時間發生了什麼事？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L17_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"<color=#ffd34c>갑자기 침식체들을 향해 달려들었네.</color>","JPN":"<color=#ffd34c>いきなり侵食体に向かって飛びかかって行った。</color>","ENG":"<color=#ffd34c>You suddenly charged straight at the C.O.s.</color>","TWN":"<color=#ffd34c>突然向侵蝕體衝了過去。</color>"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"계속 피가 끓고 있다고 중얼거리더군.","JPN":"血が沸くとずっと呟いていたぞ。","ENG":"Kept mumbling about how your blood was boiling.","TWN":"然後一直在喃喃自語，說血液在沸騰。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네가 광증에 휩싸여 침식체를 도륙할 때 확신했네.","JPN":"君が狂症にのまれて侵食体を倒す姿を見て確信したのさ。","ENG":"The moment you were consumed by madness and tore through those C.O.s, I knew for sure.","TWN":"當你陷入狂症屠殺侵蝕體時，我就確定了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그래서 자네의 피를 분석하기로 했지.","JPN":"それで、君の血液を分析しようと思った。","ENG":"So I analyzed your blood.","TWN":"所以決定分析你的血液。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"발현도가 굉장히 높더군.","JPN":"非常に高い発現度だったぞ。","ENG":"It has an incredibly high manifestation rate.","TWN":"發現其中的顯現度非常高。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"<color=#ffd34c>새로운 종</color>이라고 해도 무방할 만큼.","JPN":"もはや<color=#ffd34c>新種</color>と言っても過言ではないぐらいにね。","ENG":"Practically a <color=#ffd34c>new species</color>.","TWN":"稱之為<color=#ffd34c>新物種</color>也不為過。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그, 그러면 내 인자를 통해서…….","JPN":"じゃ、じゃあ私のファクターで……","ENG":"Th-then with my factor...","TWN":"那，那樣的話是透過我的因子……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"붉은 달 현상을 어느 정도 재현하는 데 성공했지.","JPN":"赤い月現象をある程度再現することに成功した。","ENG":"I was able to partially recreate the Red Moon phenomenon.","TWN":"成功地在一定程度上重現了紅月現象。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"이 도시는 그 과정에서 나온 일종의 부산물일세.","JPN":"この都市は、その過程で生まれたある種の副産物だよ。","ENG":"This city is merely a byproduct of that process.","TWN":"這座城市是那個過程中產生的一種副產品。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"아무래도 침식파가 자네의 무의식 속 기억에 반응한 모양이야.","JPN":"どうやら侵食波が君の無意識の中にある記憶に反応したようだね。","ENG":"It seems the Corruption rays reacted to your subconscious memories.","TWN":"看起來侵蝕波對你潛意識中的記憶產生了反應。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 미친 자식이……!","JPN":"この……！","ENG":"You're sick...!","TWN":"你這個瘋子……！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"좀 더 자부심을 가져도 좋네.","JPN":"君はもう少し誇りを持ってもいい。","ENG":"You should take pride in it.","TWN":"你可以更驕傲一點。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네는 이 현상을 일으킬 만큼 발현도가 높다는 소리니까.","JPN":"この現象を起こすほど発現度が高いというわけだからな。","ENG":"Your manifestation rate is high enough to trigger this phenomenon.","TWN":"這說明你的顯現度足以引發這種現象。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아까부터 그게 무슨 소리야?","JPN":"さっきから何を言ってるんだ？","ENG":"What are you talking about?","TWN":"嗯？剛才那是什麼聲音？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"이상 침식 현상을 연구할 때 한 가지 가설을 세웠네.","JPN":"異常侵食現象の研究の際に、ひとつの仮説を立てた。","ENG":"When studying the Aberrant Counterside Effect, I formed a hypothesis.","TWN":"在研究異常侵蝕現象時，我提出了一個假設。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"강력한 침식체가 존재만으로 주변에 영향을 끼치는 것과 같이…….","JPN":"強力な侵食体がその存在だけで周りに影響を及ぼすように……","ENG":"Just as powerful C.O.s distort their surroundings...","TWN":"強大的侵蝕體光是存在就能對周圍產生影響……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"이상 침식 현상도 강력한 무언가로 인해 나타난 현상이 아닐까?","JPN":"異常侵食現象もまた、強力な何かによって現れるものではないか。","ENG":"Perhaps the Aberrant Counterside Effect manifests due to something even greater.","TWN":"異常侵蝕現象會不會也是因為某種強大的東西引起的？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그리고 가설은 자네로 인해 증명되었네.","JPN":"その仮説は君によって証明されたのさ。","ENG":"And thanks to you, that hypothesis has been proven.","TWN":"這個假設因你得到了驗證。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"난 침식체가 아니야.","JPN":"私は侵食体じゃない。","ENG":"I'm not a C.O.!","TWN":"我不是侵蝕體。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"하지만 자네의 변이된 인자는 계속해서 침식파를 발산하고 있지.","JPN":"だが、変異した君のファクターは侵食波を発散し続けている。","ENG":"Yet your mutated factor continues to emit Corruption rays.","TWN":"但是你的變異基因仍在不斷發散侵蝕波。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네, 평소 CRF 소모가 빠른 편이라고 생각하지 않았나?","JPN":"君は普段からCRFの消耗が早いほうだと思っていなかったか？","ENG":"Your CRF consumption is unusually high, isn't it?","TWN":"你不覺得你平時消耗CRF的速度很快嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……!"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"변화한 몸의 침식 내성이 강력하기에 버티고 있을 뿐이지.","JPN":"変化した体の侵食耐性が強い分、耐えられているだけだ。","ENG":"You're only holding out because of your strong Corruption resistance.","TWN":"你只是因為身體有強大的抗侵蝕性，才能堅持下去。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"평범한 존재였다면 자네도 볼품없는 짐승으로 전락했을 걸세.","JPN":"普通の人間だったら、君も醜い獣に成り果てていただろう。","ENG":"Otherwise, you'd have turned into a mindless beast.","TWN":"如果你是個普通人的話，也會淪為一隻毫無價值的野獸。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"내 식솔들처럼 말이야.","JPN":"私の家の者のようにね。","ENG":"Like my servants.","TWN":"看，就像我的家人一樣。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래서, 그걸로 뭘 말하고 싶은 거야.","JPN":"それで、何が言いたい？","ENG":"What are you getting at?","TWN":"所以，你想說什麼？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네의 피를 머금은 것만으로도 붉은 달 현상을 재현할 수 있어.","JPN":"君の血を少し含んだだけで赤い月現象を再現できる。","ENG":"If your blood alone can recreate the Red Moon phenomenon...","TWN":"只要沾上你的血，就能重現紅月現象。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그렇다면 실제로 이 <color=#ffd34c>현상을 일으킨 자</color>는 얼마나 대단한 존재겠나?","JPN":"ならば、実際この<color=#ffd34c>現象を起こした者</color>はどれほど驚異的な存在であるだろうか！","ENG":"Then just imagine the power of <color=#ffd34c>the one who caused it</color>.","TWN":"現在知道，引發這個<color=#ffd34c>現象的人</color>到底是多麼了不起的存在了吧？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그 존재에 대해 탐구할 수 있다면……!","JPN":"その存在について探求することができれば……！","ENG":"If we could uncover the truth of that entity...!","TWN":"如果能探究那個存在的話……！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"우리는 분명 한 단계 나아가 침식을 정복할 수 있을 거란 말일세!","JPN":"我々はきっと、更なる境地へ至り、侵食を征服できるはず！","ENG":"We could finally conquer the Corruption itself!","TWN":"我們一定能更進一步，征服侵蝕！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};